    private void btn_loginActionPerformed(java.awt.event.ActionEvent evt) {//GEN-FIRST:event_btn_loginActionPerformed
        String user = txt_user.getText();
        String pass = txt_pass.getText();

        try {
            User usuario = loginService.autenticar(user, pass);
            if (usuario == null) {
                msg_erro.setText("Usuário ou senha incorretos!");
                msg_erro.setForeground(Color.RED);
                return;
            }
            if (!usuario.isAtivo()) {
                msg_erro.setText("Usuário inativo!");
                msg_erro.setForeground(Color.RED);
                return;
            }
            // Send user permission to perfil
            // Assuming MenuView has a way to set user
            MenuView menu = new MenuView();
            menu.setUser(usuario); // Assuming we add this method
            menu.setVisible(true);
            this.dispose();
        } catch (SQLException e) {
            msg_erro.setText("Erro no servidor!");
            msg_erro.setForeground(Color.RED);
        }
    }//GEN-LAST:event_btn_loginActionPerformed

    private void turnVisibleBoxActionPerformed(java.awt.event.ActionEvent evt) {//GEN-FIRST:event_turnVisibleBoxActionPerformed
        if (turnVisibleBox.isSelected()) {
            txt_pass.setEchoChar((char) 0); // Mostra a senha
        } else {
            txt_pass.setEchoChar("*");
        }
    }//GEN-LAST:event_turnVisibleBoxActionPerformed

